//! bench-hope-jar-shootoff — Monster jar vs E8 jar, head to head.
//!
//! Loads both pre-charged jars from `rknots/` and benchmarks them on the
//! same axes: capacity, disk size, resident RAM, load time, discharge
//! throughput, keys/tick. Release-only numbers (build with --release).
//!
//! The story: the Monster jar serves keys from a 1.5 MB resident table
//! (fast, but capped at 196884). The E8 jar regenerates keys from a ~3 KB
//! latent generator — 3540× the capacity, ~500× less RAM, still billions
//! of keys/s.

use distributed_inference::hope_jar::HopeJar;
use distributed_inference::hope_jar_e8::HopeJarE8;
use std::hint::black_box;
use std::time::Instant;

fn fmt_bytes(b: usize) -> String {
    if b >= 1_000_000 {
        format!("{:.2} MB", b as f64 / 1e6)
    } else if b >= 1_000 {
        format!("{:.1} KB", b as f64 / 1e3)
    } else {
        format!("{} B", b)
    }
}

fn main() {
    // ── load both jars from disk ──
    let monster_bytes = std::fs::read("rknots/hope-jar.rknot")
        .expect("rknots/hope-jar.rknot (run from distributed-inference/)");
    let e8_bytes = std::fs::read("rknots/hope-jar-e8.rknot").expect("rknots/hope-jar-e8.rknot");

    let t = Instant::now();
    let mut monster = HopeJar::decode_seeds(&monster_bytes).expect("decode monster");
    let monster_load_us = t.elapsed().as_nanos() as f64 / 1000.0;

    let t = Instant::now();
    let mut e8 = HopeJarE8::decode_rknot(&e8_bytes).expect("decode e8");
    let e8_load_us = t.elapsed().as_nanos() as f64 / 1000.0;

    assert!(monster.is_sealed() && e8.is_sealed());

    let mt = monster.telemetry();
    let et = e8.telemetry();

    // resident RAM (structural): Monster materializes all keys; E8 holds
    // only seeds + the 240 well-order lane codes.
    let monster_ram = mt.seeds_loaded * 8;
    let e8_ram = (et.seeds_loaded + 240) * 8;

    // ── discharge throughput ──
    // Monster: serve slices from the resident table (memory read).
    let mut keys_m = 0u64;
    let mut acc_m = 0u64;
    let t = Instant::now();
    for r in 0..50_000usize {
        let phase = (r % 12) as u8;
        let lane = (r % 3) as u8;
        for &k in monster.discharge(phase, lane) {
            acc_m ^= k;
            keys_m += 1;
        }
    }
    let m_dur = t.elapsed();
    let m_kps = keys_m as f64 / m_dur.as_secs_f64();
    black_box(acc_m);

    // E8: regenerate slices from the latent generator (arithmetic).
    let mut keys_e = 0u64;
    let mut acc_e = 0u64;
    let t = Instant::now();
    for r in 0..2_000usize {
        let phase = (r % 30) as u8;
        let lane = ((r / 30) % 240) as u8;
        for k in e8.discharge_iter(phase, lane) {
            acc_e ^= k;
            keys_e += 1;
        }
    }
    let e_dur = t.elapsed();
    let e_kps = keys_e as f64 / e_dur.as_secs_f64();
    black_box(acc_e);

    // ── per-slot keys ──
    let m_slot = monster.discharge(3, 1).len();
    let e_slot = e8.discharge(3, 1).len();

    let cap_ratio = et.capacity as f64 / mt.capacity as f64;
    let disk_ratio = monster_bytes.len() as f64 / e8_bytes.len() as f64;
    let ram_ratio = monster_ram as f64 / e8_ram as f64;

    let row = |label: &str, m: String, e: String| {
        println!("{:<20} {:>18} {:>18}", label, m, e);
    };

    println!("=== HOPE JAR SHOOTOFF — Monster vs E8 (release, warm) ===\n");
    println!("{:<20} {:>18} {:>18}", "", "MONSTER", "E8");
    println!("{:-<58}", "");
    row(
        "capacity (keys)",
        mt.capacity.to_string(),
        et.capacity.to_string(),
    );
    row(
        "structure",
        "12ph × 3lanes".into(),
        "30ph × 240lanes".into(),
    );
    row(
        "disk size",
        fmt_bytes(monster_bytes.len()),
        fmt_bytes(e8_bytes.len()),
    );
    row("resident RAM", fmt_bytes(monster_ram), fmt_bytes(e8_ram));
    row("keys: stored?", "materialized".into(), "LATENT".into());
    row(
        "load from disk",
        format!("{:.1} us", monster_load_us),
        format!("{:.1} us", e8_load_us),
    );
    row("keys / slot", m_slot.to_string(), e_slot.to_string());
    row(
        "discharge M keys/s",
        format!("{:.0}", m_kps / 1e6),
        format!("{:.0}", e_kps / 1e6),
    );
    println!("{:-<58}", "");
    println!();
    println!("E8 advantage:");
    println!(
        "  capacity : {:.0}x more keys ({} vs {})",
        cap_ratio, et.capacity, mt.capacity
    );
    println!("  disk     : {:.0}x smaller", disk_ratio);
    println!(
        "  RAM      : {:.0}x less resident ({} vs {})",
        ram_ratio,
        fmt_bytes(e8_ram),
        fmt_bytes(monster_ram)
    );
    println!("  + O(1) predict() point query the Monster jar has no equivalent for");

    // E8-only: predict() throughput
    let n = 20_000_000u64;
    let mut acc = 0u64;
    let t = Instant::now();
    for i in 0..n {
        acc ^= e8.predict(i.wrapping_mul(2654435761));
    }
    let pdur = t.elapsed();
    black_box(acc);
    println!(
        "    predict(): {:.0} M ops/s, {:.2} ns/query",
        n as f64 / pdur.as_secs_f64() / 1e6,
        pdur.as_nanos() as f64 / n as f64
    );
}
